t.script:
(function () {
  'use strict';

  var wrapEl     = document.getElementById('steps-flow-wrap');
  var csrfToken  = wrapEl ? (wrapEl.getAttribute('data-csrf') || '') : '';
  var chatbotId  = wrapEl ? parseInt(wrapEl.getAttribute('data-chatbot-id') || '0', 10) : 0;
  var tree       = ;

  /* ── Step type config ── */
  var TYPE = {
    message:              { icon: '💬', label: 'Message',           color: '#1a73e8', bg: '#e8f0fe', border: '#93c5fd' },
    question_text:        { icon: '✎',   label: 'Question',          color: '#7c3aed', bg: '#f5f3ff', border: '#c4b5fd' },
    question_numeric:     { icon: '🔢', label: 'Number',            color: '#ea580c', bg: '#fff7ed', border: '#fdb57a' },
    question_phone:       { icon: '📱', label: 'Phone',             color: '#0891b2', bg: '#ecfeff', border: '#67e8f9' },
    question_email:       { icon: '💌', label: 'Email',             color: '#4f46e5', bg: '#eef2ff', border: '#a5b4fc' },
    question_date:        { icon: '📅', label: 'Date',              color: '#be185d', bg: '#fdf2f8', border: '#f9a8d4' },
    question_document:    { icon: '📄', label: 'Document',          color: '#475569', bg: '#f8fafc', border: '#cbd5e1' },
    question_image:       { icon: '🖼', label: 'Image',             color: '#b45309', bg: '#fffbeb', border: '#fcd34d' },
    question_video:       { icon: '🎥', label: 'Video',             color: '#dc2626', bg: '#fef2f2', border: '#fca5a5' },
    question_audio:       { icon: '🎵', label: 'Audio',             color: '#db2777', bg: '#fdf2f8', border: '#f9a8d4' },
    question_interactive: { icon: '🔴', label: 'Interactive',       color: '#0284c7', bg: '#f0f9ff', border: '#7dd3fc' },
    set_variable:         { icon: '📝', label: 'Set Variable',      color: '#d97706', bg: '#fffbeb', border: '#fcd34d' },
    execute_code:         { icon: '⚡',   label: 'Execute Code',      color: '#374151', bg: '#f3f4f6', border: '#9ca3af' },
    end_flow:             { icon: '✔',  label: 'End Flow',          color: '#16a34a', bg: '#f0fdf4', border: '#86efac' },
  };
  var DEFAULT_TYPE = { icon: '●', label: 'Step', color: '#6b7280', bg: '#f9fafb', border: '#e5e7eb' };

  /* ── Zoom ── */
  var ZOOM_MIN = 0.4, ZOOM_MAX = 2.0, ZOOM_STEP = 0.1;
  var zoomLevel = 1;
  var activeGrid = null;
  var redrawLines = null;

  function clamp(v, lo, hi) { return Math.min(hi, Math.max(lo, v)); }

  function updateZoomLabel() {
    var el = document.getElementById('bbZoomLabel');
    if (el) el.textContent = Math.round(zoomLevel * 100) + '%';
  }
  function applyZoom() {
    if (!activeGrid) return;
    activeGrid.style.transform = 'scale(' + zoomLevel + ')';
    activeGrid.style.transformOrigin = 'top center';
    updateZoomLabel();
    if (typeof redrawLines === 'function') redrawLines();
  }
  function setZoom(z) {
    var nz = clamp(z, ZOOM_MIN, ZOOM_MAX);
    if (nz === zoomLevel) return;
    zoomLevel = nz;
    applyZoom();
  }
  function bindZoom() {
    var plus  = document.getElementById('bbZoomIn');
    var minus = document.getElementById('bbZoomOut');
    var wrap  = document.getElementById('steps-flow-wrap');
    if (plus)  plus.addEventListener('click',  function () { setZoom(zoomLevel + ZOOM_STEP); });
    if (minus) minus.addEventListener('click', function () { setZoom(zoomLevel - ZOOM_STEP); });
    if (wrap) {
      wrap.addEventListener('wheel', function (ev) {
        if (!ev.ctrlKey) return;
        ev.preventDefault();
        setZoom(zoomLevel + (ev.deltaY < 0 ? ZOOM_STEP : -ZOOM_STEP));
      }, { passive: false });
    }
    updateZoomLabel();
  }

  /* ── Tree helpers ── */
  function flatten(nodes, level, parent, out) {
    level  = level  || 0;
    parent = parent || null;
    out    = out    || [];
    (nodes || []).forEach(function (n) {
      out.push({
        id:           n.id,
        name:         n.name,
        type:         n.type,
        level:        level,
        parent:       parent,
        children:     n.children     || [],
        preview_html: n.preview_html || '',
        answers:      n.answers      || [],
        variables:    n.variables    || [],
      });
      flatten(n.children || [], level + 1, n.id, out);
    });
    return out;
  }
  function maxLevel(a) { return a.reduce(function (m, n) { return Math.max(m, n.level); }, 0); }
  function groupBy(a, k) {
    var m = {};
    a.forEach(function (x) { (m[x[k]] = m[x[k]] || []).push(x); });
    return m;
  }
  function enhanceLinks(el) {
    el.querySelectorAll('a').forEach(function (a) { a.target = '_blank'; a.rel = 'noopener noreferrer'; });
  }

  /* ── JSON-RPC helper ── */
  function rpc(model, method, args, kwargs) {
    var pathname = window.location.pathname || '';
    var base = (pathname.indexOf('/chatbot/') >= 0) ? pathname.replace(/\/chatbot\/.*$/, '') : '';
    var payload = {
      jsonrpc: '2.0', method: 'call',
      params:  { model: model, method: method, args: args || [], kwargs: kwargs || {} },
      id:      Math.floor(Math.random() * 99999999),
    };
    return fetch(base + '/web/dataset/call_kw/' + model + '/' + method, {
      method:      'POST',
      credentials: 'same-origin',
      headers: {
        'Content-Type':     'application/json',
        'X-Requested-With': 'XMLHttpRequest',
        'X-CSRFToken':      csrfToken || '',
      },
      body: JSON.stringify(payload),
    }).then(function (r) { return r.json(); });
  }

  /* ── Modal (iframe popup) ── */
  var _modalEl   = null;
  var _modalPoll = null;

  function closeModal() {
    if (_modalPoll) { clearInterval(_modalPoll); _modalPoll = null; }
    if (_modalEl)   { _modalEl.remove(); _modalEl = null; }
    window.location.reload();
  }

  function openModal(iframeUrl, title) {
    if (_modalEl)   { _modalEl.remove(); }
    if (_modalPoll) { clearInterval(_modalPoll); _modalPoll = null; }

    var overlay = document.createElement('div');
    overlay.className = 'bb-modal-overlay';
    _modalEl = overlay;

    var modal = document.createElement('div');
    modal.className = 'bb-modal';

    /* Header bar */
    var hdr = document.createElement('div');
    hdr.className = 'bb-modal-hdr';

    var titleEl = document.createElement('span');
    titleEl.className = 'bb-modal-title';
    titleEl.textContent = title;
    hdr.appendChild(titleEl);

    var hint = document.createElement('span');
    hint.className = 'bb-modal-hint';
    hint.textContent = 'Save your changes inside, then click Done to refresh the flow.';
    hdr.appendChild(hint);

    var doneBtn = document.createElement('button');
    doneBtn.type = 'button';
    doneBtn.className = 'bb-modal-btn bb-modal-done';
    doneBtn.innerHTML = '✓ Done & Refresh';
    doneBtn.addEventListener('click', closeModal);
    hdr.appendChild(doneBtn);

    var closeBtn = document.createElement('button');
    closeBtn.type = 'button';
    closeBtn.className = 'bb-modal-btn bb-modal-x';
    closeBtn.innerHTML = '×';
    closeBtn.title = 'Close without refreshing';
    closeBtn.addEventListener('click', function () {
      if (_modalPoll) { clearInterval(_modalPoll); _modalPoll = null; }
      if (_modalEl)   { _modalEl.remove(); _modalEl = null; }
    });
    hdr.appendChild(closeBtn);

    /* Iframe */
    var frame = document.createElement('iframe');
    frame.src = iframeUrl;
    frame.className = 'bb-modal-frame';

    /* Hide Odoo's top navbar inside the iframe once it loads */
    frame.addEventListener('load', function () {
      try {
        var doc = frame.contentDocument;
        if (!doc || !doc.head) return;
        var s = doc.createElement('style');
        s.textContent =
          '.o_main_navbar{display:none!important}' +
          '.o_web_client{padding-top:0!important}' +
          '.o_action_manager{padding-top:0!important}';
        doc.head.appendChild(s);
      } catch (ex) { /* cross-origin guard */ }
    });

    /* Auto-detect save: when iframe title stops starting with "New"
       (Odoo sets title to record name after first save), close + reload. */
    var _seenNew = false;
    _modalPoll = setInterval(function () {
      try {
        var doc = frame.contentDocument;
        if (!doc) return;
        var t = doc.title || '';
        if (!_seenNew && t.toLowerCase().indexOf('new') !== -1) { _seenNew = true; }
        if (_seenNew && t && t.toLowerCase().indexOf('new') === -1) {
          clearInterval(_modalPoll); _modalPoll = null;
          setTimeout(closeModal, 500);
        }
      } catch (ex) { /* guard */ }
    }, 700);

    modal.appendChild(hdr);
    modal.appendChild(frame);
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
  }

  /* ESC closes modal without refreshing */
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && _modalEl) {
      if (_modalPoll) { clearInterval(_modalPoll); _modalPoll = null; }
      _modalEl.remove(); _modalEl = null;
    }
  });

  function openStepModal(stepId) {
    openModal('/web#model=whatsapp.chatbot.step&view_type=form&id=' + stepId, 'Edit Step');
  }
  function openAddStepModal(parentStepId) {
    rpc('whatsapp.chatbot.step', 'create', [{
      chatbot_id: chatbotId,
      parent_id:  parentStepId,
      name:       'New Step',
    }]).then(function (result) {
      var stepId = (result && result.result) ? result.result : false;
      if (stepId) {
        openModal('/web#model=whatsapp.chatbot.step&view_type=form&id=' + stepId, 'New Step');
      } else {
        alert('Failed to create step: ' + ((result && result.error && result.error.data && result.error.data.message) || 'Unknown error.'));
      }
    }).catch(function (err) { alert('Network error: ' + err); });
  }

  /* ── Inline name save ── */
  function saveStepName(stepId, newName) {
    rpc('whatsapp.chatbot.step', 'write', [[stepId], { name: newName }])
      .catch(function () {});
  }

  /* ── Build card DOM ── */
  function buildCard(node) {
    var cfg = TYPE[node.type] || DEFAULT_TYPE;

    var card = document.createElement('div');
    card.className = 'bb-card bb-card-' + (node.type || 'step');
    card.dataset.id = node.id;
    if (node.parent) card.dataset.parent = node.parent;
    card.style.setProperty('--cc', cfg.color);
    card.style.setProperty('--cb', cfg.bg);
    card.style.setProperty('--ce', cfg.border);

    /* Header */
    var header = document.createElement('div');
    header.className = 'bb-card-header';

    var iconEl = document.createElement('span');
    iconEl.className = 'bb-card-icon';
    iconEl.innerHTML = cfg.icon;
    header.appendChild(iconEl);

    var titleEl = document.createElement('span');
    titleEl.className = 'bb-card-title';
    titleEl.textContent = node.name || ('Step #' + node.id);
    titleEl.contentEditable = 'true';
    titleEl.title = 'Click to rename (letters, spaces and dashes only)';
    var originalName = titleEl.textContent;

    titleEl.addEventListener('focus',   function () { originalName = this.textContent; });
    titleEl.addEventListener('keydown', function (e) {
      if (e.key === 'Enter')  { e.preventDefault(); this.blur(); }
      if (e.key === 'Escape') { this.textContent = originalName; this.blur(); }
    });
    titleEl.addEventListener('paste', function (e) {
      e.preventDefault();
      var text = (e.clipboardData || window.clipboardData).getData('text/plain');
      document.execCommand('insertText', false, text);
    });
    titleEl.addEventListener('blur', function () {
      var newName = this.textContent.trim();
      if (!newName)                    { this.textContent = originalName; return; }
      if (newName === originalName)    { return; }
      if (!/^[A-Za-z\s-]+$/.test(newName)) {
        this.textContent = originalName;
        alert('Name can only contain letters, spaces and dashes.');
        return;
      }
      saveStepName(node.id, newName);
      originalName = newName;
    });
    titleEl.addEventListener('mousedown', function (e) { e.stopPropagation(); });
    header.appendChild(titleEl);

    var chipEl = document.createElement('span');
    chipEl.className = 'bb-type-chip';
    chipEl.textContent = cfg.label;
    header.appendChild(chipEl);

    card.appendChild(header);

    /* Body */
    var body = document.createElement('div');
    body.className = 'bb-card-body';

    if (node.preview_html) {
      var bubble = document.createElement('div');
      bubble.className = 'wa-bubble';
      var bubbleBody = document.createElement('div');
      bubbleBody.className = 'wa-bubble-body';
      bubbleBody.innerHTML = node.preview_html;
      enhanceLinks(bubbleBody);
      bubble.appendChild(bubbleBody);
      body.appendChild(bubble);
    }

    if (node.answers && node.answers.length) {
      var answerRow = document.createElement('div');
      answerRow.className = 'bb-chips bb-chips-answer';
      node.answers.forEach(function (txt) {
        var chip = document.createElement('span');
        chip.className = 'bb-chip bb-chip-answer';
        chip.textContent = txt;
        answerRow.appendChild(chip);
      });
      body.appendChild(answerRow);
    }

    if (node.variables && node.variables.length) {
      var varRow = document.createElement('div');
      varRow.className = 'bb-chips bb-chips-var';
      node.variables.forEach(function (txt) {
        var chip = document.createElement('span');
        chip.className = 'bb-chip bb-chip-var';
        chip.textContent = txt;
        varRow.appendChild(chip);
      });
      body.appendChild(varRow);
    }

    card.appendChild(body);

    /* Footer */
    var footer = document.createElement('div');
    footer.className = 'bb-card-footer';

    var editBtn = document.createElement('button');
    editBtn.type = 'button';
    editBtn.className = 'bb-foot-btn bb-edit-btn';
    editBtn.innerHTML = 'Edit';
    editBtn.addEventListener('click', function (e) { e.stopPropagation(); openStepModal(node.id); });
    footer.appendChild(editBtn);

    var delBtn = document.createElement('button');
    delBtn.type = 'button';
    delBtn.className = 'bb-foot-btn bb-del-btn';
    delBtn.innerHTML = 'Delete';
    delBtn.addEventListener('click', function (e) {
      e.stopPropagation();
      if (!confirm('Delete this step? This cannot be undone.')) return;
      var body = new URLSearchParams({ csrf_token: csrfToken });
      fetch('/chatbot/step/' + node.id + '/delete', {
        method:  'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'X-CSRF-TOKEN': csrfToken },
        body:    body.toString(),
      }).then(function (r) {
        return r.text().then(function (text) {
          var data = {};
          try { data = JSON.parse(text); } catch (ex) {}
          if (r.ok && data.success) { window.location.href = '/chatbot/steps/' + chatbotId; }
          else alert(data.error || 'Could not delete step.');
        });
      }).catch(function () { alert('Request failed. Please try again.'); });
    });
    footer.appendChild(delBtn);
    card.appendChild(footer);

    /* Add-child button (bottom centre) */
    var addBtn = document.createElement('button');
    addBtn.type = 'button';
    addBtn.className = 'bb-add-step';
    addBtn.title = 'Add next step';
    addBtn.innerHTML = '';
    addBtn.dataset.parentId = node.id;
    addBtn.addEventListener('click', function (e) {
      e.preventDefault(); e.stopPropagation();
      openAddStepModal(parseInt(this.dataset.parentId, 10));
    });
    card.appendChild(addBtn);

    return card;
  }

  /* ── Render flow ── */
  function renderFlow() {
    var wrap  = document.getElementById('steps-flow-wrap');
    var grid  = document.getElementById('steps-flow');
    activeGrid = grid;

    /* Ensure SVG is in grid */
    var svg = grid.querySelector('#bb-lines');
    if (!svg) {
      svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      svg.id = 'bb-lines'; svg.classList.add('bb-lines');
      grid.prepend(svg);
    }

    var empty = document.getElementById('bb-empty');
    svg.innerHTML = '';
    grid.querySelectorAll('.bb-row').forEach(function (r) { r.remove(); });

    var flat = flatten(tree);
    if (!flat.length) { empty.style.display = ''; return; }
    empty.style.display = 'none';

    var nRows   = maxLevel(flat) + 1;
    var byLevel = groupBy(flat, 'level');

    for (var row = 0; row < nRows; row++) {
      var rowEl = document.createElement('div');
      rowEl.className = 'bb-row';
      (byLevel[row] || []).forEach(function (node) {
        rowEl.appendChild(buildCard(node));
      });
      grid.appendChild(rowEl);
    }

    /* Draw SVG connectors */
    function drawLines() {
      var w = grid.scrollWidth, h = grid.scrollHeight;
      svg.setAttribute('width', w);  svg.setAttribute('height', h);
      svg.style.width = w + 'px';    svg.style.height = h + 'px';
      svg.innerHTML = '';

      /* Arrow marker */
      var defs   = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
      var marker = document.createElementNS('http://www.w3.org/2000/svg', 'marker');
      marker.setAttribute('id', 'bb-arrow');
      marker.setAttribute('markerWidth', '7');   marker.setAttribute('markerHeight', '7');
      marker.setAttribute('refX', '0');          marker.setAttribute('refY', '3.5');
      marker.setAttribute('orient', 'auto');     marker.setAttribute('markerUnits', 'strokeWidth');
      var mp = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      mp.setAttribute('d', 'M0,0 L0,7 L5,3.5 z');
      mp.setAttribute('fill', '#9ca3af');
      marker.appendChild(mp); defs.appendChild(marker); svg.appendChild(defs);

      var gridRect = grid.getBoundingClientRect();
      var byId = {};
      grid.querySelectorAll('.bb-card').forEach(function (c) { byId[c.dataset.id] = c; });

      var ADD_BTN_OFFSET = 14; /* .bb-add-step sits 14 px below the card */

      grid.querySelectorAll('.bb-card').forEach(function (child) {
        var pid = child.dataset.parent; if (!pid) return;
        var par = byId[pid];            if (!par) return;

        var pr = par.getBoundingClientRect();
        var cr = child.getBoundingClientRect();

        /* Vertical bezier: centre-bottom → centre-top */
        var x1 = pr.left + pr.width  / 2 - gridRect.left;
        var y1 = pr.bottom - gridRect.top + ADD_BTN_OFFSET;
        var x2 = cr.left  + cr.width  / 2 - gridRect.left;
        var y2 = cr.top   - gridRect.top;
        if (isNaN(x1) || isNaN(y1) || isNaN(x2) || isNaN(y2)) return;

        var my = (y1 + y2) / 2;
        var path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        path.setAttribute('d', 'M ' + x1 + ' ' + y1 +
          ' C ' + x1 + ' ' + my + ', ' + x2 + ' ' + my + ', ' + x2 + ' ' + y2);
        path.setAttribute('class', 'bb-connector');
        path.setAttribute('marker-end', 'url(#bb-arrow)');
        svg.appendChild(path);
      });
    }

    redrawLines = drawLines;
    setTimeout(function () { drawLines(); setTimeout(drawLines, 150); }, 80);
    window.addEventListener('resize', drawLines, { passive: true });
    applyZoom();
    enableDragScroll(wrap);
  }

  /* ── Drag-to-pan ── */
  function enableDragScroll(el) {
    var dragging = false, sx = 0, sy = 0, ssl = 0, sst = 0;
    el.addEventListener('mousedown', function (e) {
      if (e.button !== 0) return;
      var t = e.target;
      if (t.closest('[contenteditable]') || t.closest('button') || t.closest('a')) return;
      dragging = true; el.classList.add('bb-dragging');
      sx = e.clientX; sy = e.clientY; ssl = el.scrollLeft; sst = el.scrollTop;
      e.preventDefault();
    });
    window.addEventListener('mousemove', function (e) {
      if (!dragging) return;
      el.scrollLeft = ssl - (e.clientX - sx);
      el.scrollTop  = sst - (e.clientY - sy);
    }, { passive: true });
    window.addEventListener('mouseup', function () { dragging = false; el.classList.remove('bb-dragging'); });

    el.addEventListener('touchstart', function (e) {
      var t = e.touches && e.touches[0]; if (!t) return;
      dragging = true; el.classList.add('bb-dragging');
      sx = t.clientX; sy = t.clientY; ssl = el.scrollLeft; sst = el.scrollTop;
    }, { passive: true });
    el.addEventListener('touchmove', function (e) {
      if (!dragging) return;
      var t = e.touches && e.touches[0]; if (!t) return;
      el.scrollLeft = ssl - (t.clientX - sx);
      el.scrollTop  = sst - (t.clientY - sy);
    }, { passive: true });
    el.addEventListener('touchend', function () { dragging = false; el.classList.remove('bb-dragging'); });
  }

  /* ── Init ── */
  bindZoom();
  renderFlow();
})();
